@section('javascript')
    <script>
        fetch('http://localhost:8000/api/candidatures')
            .then(response => response.json())
            .then(res => {
                //console.log('Candidatures (raw):', res);
                const payload = Array.isArray(res) ? res : (res && res.data ? res.data : res);

                if (!Array.isArray(payload) || payload.length === 0) {
                    console.warn('API returned no candidates or unexpected shape', payload);
                    candidates = [];
                    buildPipeline();
                    if (typeof showToast === 'function') showToast('Aucune candidature trouvée');
                    return;
                }

                candidates = payload.map(item => ({
                    id: item.id ? String(item.id) : uid(),
                    nom: item.fullName || item.full_name || item.nom || '—',
                    email: item.email || item.email_address || '',
                    telephone: item.phone || item.telephone || item.phone_number || '',
                    poste: item.slug || item.poste || item.job || '',
                    sourcing: item.sourcing || item.source || 'API',
                    stage: item.stage || item.statut || item.status || 'sourcing',
                }));

                buildPipeline();
                // log counts per stage for debug
                const counts = STAGES.map(s => `${s.id}:${candidates.filter(c => c.stage === s.id).length}`).join(', ');
                //console.log('Counts by stage:', counts);
                if (typeof showToast === 'function') showToast(`${candidates.length} candidature(s) chargée(s)`);
            })
            .catch(error => {
                console.error('Error:', error);
                if (typeof showToast === 'function') showToast('Erreur lors du chargement de l\'API');
            });

        const STAGES = [
            { id: "sourcing", label: "Sourcing" },
            { id: "prequalif", label: "Prequalif" },
            { id: "entretien_rh", label: "Entretien RH" },
            { id: "entretien_tech", label: "Entretien Technique" },
            { id: "entretien_final", label: "Entretien Final" },
        ];

        // Pas de données locales : utiliser uniquement l'API
        let candidates = [];

        function uid() { return Math.random().toString(36).slice(2, 10); }

        function buildPipeline() {
            const root = document.getElementById("pipeline");
            root.innerHTML = "";
            STAGES.forEach((stage, idx) => {
                const col = document.createElement("div");
                col.className = "stage-col rounded-xl p-4 drop-zone";
                col.dataset.stage = stage.id;

                const inStage = candidates.filter(c => c.stage === stage.id);

                col.innerHTML = `
            <div class="flex items-center justify-between mb-3">
              <p class="text-slate-900 font-semibold">${stage.label}</p>
              <span class="text-xs text-slate-500 bg-slate-100 px-2 py-1 rounded-full">${inStage.length}</span>
            </div>
            <div class="flex flex-col gap-3" id="col-${stage.id}"></div>
          `;
                root.appendChild(col);

                const list = col.querySelector(`#col-${stage.id}`);
                inStage.forEach(c => list.appendChild(candidateCard(c, idx)));

                // Drag & drop
                col.addEventListener("dragover", e => { e.preventDefault(); col.classList.add("drag-over"); });
                col.addEventListener("dragleave", () => col.classList.remove("drag-over"));
                col.addEventListener("drop", e => {
                    e.preventDefault();
                    col.classList.remove("drag-over");
                    const id = e.dataTransfer.getData("text/plain");
                    moveCandidate(id, stage.id);
                });
            });
            document.getElementById("totalCounter").textContent = `Total : ${candidates.length} candidat(s)`;
            updatePlanifCandidates();
        }

        function updatePlanifCandidates() {
            const select = document.getElementById('pCandidat');
            if (!select) return;
            const rhCandidates = candidates.filter(c => c.stage === 'entretien_rh');
            select.innerHTML = '<option value="" disabled selected>Candidat</option>';
            rhCandidates.forEach(c => {
                const option = document.createElement('option');
                option.value = c.id;
                option.textContent = `${c.nom} — ${c.poste}`;
                select.appendChild(option);
            });
        }

        function candidateCard(c, idx) {
            const el = document.createElement("div");
            el.className = "candidate-card rounded-lg p-3 cursor-grab";
            el.draggable = true;
            el.dataset.id = c.id;

            el.innerHTML = `
          <div class="font-semibold text-dark">${escapeHtml(c.nom)}</div>
          <!--<div class="text-xs text-gray-400 mt-1">//${escapeHtml(c.email)}</div>-->
          <div class="text-sm text-gray-500">${escapeHtml(c.telephone)}</div>
          <div class="text-sm text-gray-600 mb-3">${escapeHtml(c.poste)}</div>
          <!--<div class="text-xs text-emerald-400 mb-3">Source : /*${escapeHtml(c.sourcing)}*/</div>-->
          <div class="flex flex-col gap-1.5 text-sm">
            ${idx < STAGES.length - 1
                    ? `<a href="#" class="link-next" data-action="next">Passer à l'étape suivante</a>`
                    : `<span class="text-emerald-400">✓ Dernier stade</span>`}
            ${c.stage === 'entretien_rh'
                    ? `<a href="mailto:${encodeURIComponent(c.email)}?subject=${encodeURIComponent('Convocation à un entretien RH d`embauche - pour Poste de : '+ c.poste + ' chez Sispay Groupe')}&body=${encodeURIComponent('Bonjour ' + c.nom + ', Notre équipe RH souhaite vous contacter pour un entretien. Cordialement,')}"><span class="text-sky-400">Envoyer email RH</span></a>`
                    : ''}        ${idx > STAGES.findIndex(s => s.id === 'entretien_rh') && c.email
                        ? `<a href="mailto:${encodeURIComponent(c.email)}?subject=${encodeURIComponent('Suivi entretien')}&body=${encodeURIComponent('Bonjour ' + c.nom + ', Notre équipe souhaite faire le point après votre entretien. Cordialement,')}" class="text-sky-400">Envoyer email de suivi</a>`
                        : ''}        <a href="#" class="link-del" data-action="delete">Supprimer candidat</a>
          </div>
        `;

            el.addEventListener("dragstart", e => {
                e.dataTransfer.setData("text/plain", c.id);
                el.style.opacity = "0.5";
            });
            el.addEventListener("dragend", () => { el.style.opacity = "1"; });

            el.querySelector('[data-action="next"]')?.addEventListener("click", e => {
                e.preventDefault();
                if (STAGES[idx + 1]) moveCandidate(c.id, STAGES[idx + 1].id);
            });
            el.querySelector('[data-action="delete"]')?.addEventListener("click", e => {
                e.preventDefault();
                if (confirm(`Supprimer "${c.nom}" ?`)) {
                    candidates = candidates.filter(x => x.id !== c.id);
                    buildPipeline();
                    showToast("Candidat supprimé");
                }
            });

            return el;
        }

        function moveCandidate(id, newStage) {
            const c = candidates.find(x => x.id === id);
            if (!c) return;
            c.stage = newStage;
            buildPipeline();
            showToast(`Déplacé vers : ${STAGES.find(s => s.id === newStage).label}`);
        }

        document.getElementById('planifForm')?.addEventListener('submit', e => {
            e.preventDefault();
            const candidateId = document.getElementById('pCandidat').value;
            const type = document.getElementById('pType').value;
            const date = document.getElementById('pDate').value;
            const mode = document.getElementById('pMode').value;
            const evaluateur = document.getElementById('pEvaluateur').value.trim();
            const candidate = candidates.find(c => c.id === candidateId);

            if (!candidate) {
                showToast('Sélectionnez un candidat en entretien RH');
                return;
            }
            const planifList = document.getElementById('planifList');
            const card = document.createElement('div');
            card.className = 'card-dark rounded-xl p-4';
            card.innerHTML = `
          <div class="flex flex-col gap-2 md:flex-row md:justify-between md:items-center">
            <div>
              <div class="text-white font-semibold">${escapeHtml(candidate.nom)} - ${escapeHtml(type)}</div>
              <div class="text-sm text-gray-400">${escapeHtml(candidate.poste)} • ${escapeHtml(mode)}</div>
              <div class="text-sm text-gray-400">${new Date(date).toLocaleString('fr-FR')}</div>
              <div class="text-sm text-white/80">Evaluateur : ${escapeHtml(evaluateur)}</div>
            </div>
            <a href="mailto:${encodeURIComponent(candidate.email)}?subject=${encodeURIComponent(type + ' - planification')}&body=${encodeURIComponent('Bonjour ' + candidate.nom + ',%0D%0A%0D%0AVotre entretien ' + type + ' est planifié le ' + new Date(date).toLocaleString('fr-FR') + ' en mode ' + mode + '.%0D%0A%0D%0ACordialement,')}" class="btn-add text-white px-4 py-2 rounded-lg whitespace-nowrap">Envoyer email</a>
          </div>
        `;
            planifList.prepend(card);
            showToast('Entretien planifié');
            e.target.reset();
            updatePlanifCandidates();
        });

        function escapeHtml(s) {
            return String(s).replace(/[&<>"']/g, m => ({
                "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;"
            }[m]));
        }

        function showToast(msg) {
            const t = document.getElementById("toast");
            t.textContent = msg;
            t.classList.remove("hidden");
            clearTimeout(showToast._tmr);
            showToast._tmr = setTimeout(() => t.classList.add("hidden"), 2200);
        }

        // Retourne tous les candidats au stade "sourcing" et peuple la table #sym:candidates si présente
        function getSourcingCandidates() {
            const list = candidates.filter(c => c.stage === 'sourcing');
            console.log('Sourcing candidates:', list);
            const table = document.getElementById('sym:candidates');
            if (!table) return list;

            // Si c'est un <table>, construire un tbody. Sinon, injecter une liste simple.
            if (table.tagName.toLowerCase() === 'table') {
                let tbody = table.querySelector('tbody');
                if (!tbody) {
                    tbody = document.createElement('tbody');
                    table.appendChild(tbody);
                }
                tbody.innerHTML = '';
                list.forEach(c => {
                    const tr = document.createElement('tr');
                    tr.innerHTML = `
              <td>${escapeHtml(c.nom)}</td>
              <td>${escapeHtml(c.poste)}</td>
              <td>${escapeHtml(c.telephone)}</td>
              <td>${escapeHtml(c.email)}</td>
            `;
                    tbody.appendChild(tr);
                });
            } else {
                // non-table container
                table.innerHTML = '';
                const ul = document.createElement('ul');
                list.forEach(c => {
                    const li = document.createElement('li');
                    li.textContent = `${c.nom} — ${c.poste} — ${c.telephone} — ${c.email}`;
                    ul.appendChild(li);
                });
                table.appendChild(ul);
            }
            showToast(`${list.length} en sourcing`);
            return list;
        }

        // Crée un bouton d'action si absent et attache l'event listener
        (function ensureSourcingButton() {
            const existing = document.getElementById('btnSourcing');
            if (existing) {
                existing.removeEventListener('click', getSourcingCandidates);
                existing.addEventListener('click', getSourcingCandidates);
                return;
            }
            const btn = document.createElement('button');
            btn.id = 'btnSourcing';
            btn.type = 'button';
            btn.textContent = 'Afficher sourcing';
            btn.className = 'ml-3 px-3 py-1 rounded bg-slate-700 text-white text-sm';
            btn.addEventListener('click', getSourcingCandidates);
            const tc = document.getElementById('totalCounter');
            if (tc && tc.parentNode) tc.parentNode.appendChild(btn);
            else document.body.appendChild(btn);
        })();

        // Form submission
        document.getElementById("addForm").addEventListener("submit", e => {
            e.preventDefault();
            const nom = document.getElementById("nom").value.trim();
            const email = document.getElementById("email").value.trim();
            const telephone = document.getElementById("telephone").value.trim();
            const poste = document.getElementById("poste").value.trim();
            const sourcing = document.getElementById("sourcing").value;
            if (!nom || !email || !telephone || !poste || !sourcing) return;

            candidates.push({
                id: uid(), nom, email, telephone, poste, sourcing, stage: "sourcing"
            });
            e.target.reset();
            buildPipeline();
            showToast("Candidat ajouté !");
        });

        // Initial render
        buildPipeline();

    </script>
@endsection